import{_ as d,o as i,c as s,ag as c}from"./chunks/framework.CAXxHpAX.js";const b=JSON.parse('{"title":"1949-1956年：过渡时期（新民主主","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-40.md","filePath":"notes/note-40.md"}'),l={name:"notes/note-40.md"};function v(r,a,e,o,t,n){return i(),s("div",null,[...a[0]||(a[0]=[c('<h1 id="_1949-1956年-过渡时期-新民主主" tabindex="-1">1949-1956年：过渡时期（新民主主 <a class="header-anchor" href="#_1949-1956年-过渡时期-新民主主" aria-label="Permalink to &quot;1949-1956年：过渡时期（新民主主&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、1949-1956年：</span>过渡时期（新民主主义国家——社会主义国家）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、社会主义制度的建立（社会主义初级阶段）：</span>1956年三大改造完成</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、社会主义建设的探索：</span>1956-1976年（1956-1966年全面建设社会主义十年）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、1956-1966年全面建设社会主义十年成就：</span>大庆、胜利油田；兰新、兰青、包兰铁路、人工合成结晶牛胰岛素；1964，原子弹试验成功</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、1966-1976年文革建设成就：</span>1966，导弹实验成功；1967，氢弹实验成功；1970，发射人造地球卫星——东方红一号；1973，袁隆平，籼型杂交水稻。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、两弹一星：</span>核弹（原子弹、氢弹）导弹和人造地球卫星</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、中共八大：</span>1956年，分析主要矛盾，任务：落后农业国——先进工业国；探索建设社会主义道路的良好开端。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、社会主义建设成就的影响：</span>初步形成了独立的、比较完整的工业体系和国民经济体系，为现代化建设打下了坚实的物质基础。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、开始改变工业落后的面貌，向社会主义工业化迈进：</span>一五计划。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p>1</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">0、三大改造的实质和意义：</span>实现生产资料私有制向社会主义公有制转变；标志着社会主义基本制度在我国建立，进入社会主义初级阶段。</p></div><div class="circle-overlay"></div></div></div>',12)])])}const y=d(l,[["render",v]]);export{b as __pageData,y as default};
